const AREA_LIST = [...new Set(EVENTS.map(e => e.area))];

const MONTH_ORDER = { Jan:1, Feb:2, Mar:3, Apr:4, May:5, Jun:6, Jul:7, Aug:8, Sep:9, Oct:10, Nov:11, Dec:12 };
function sortByDate(events) {
  return [...events].sort((a, b) => {
    const parse = d => {
      const m = d.match(/^([A-Za-z]+)\s*(\d+)?/);
      if (!m) return 999;
      return (MONTH_ORDER[m[1]] || 99) * 100 + (parseInt(m[2]) || 0);
    };
    return parse(a.date) - parse(b.date);
  });
}

/* ============ HOOKS & STYLES ============ */
function useWindowSize() {
  const [w, setW] = useState(typeof window !== "undefined" ? window.innerWidth : 1200);
  useEffect(() => { const h = () => setW(window.innerWidth); window.addEventListener("resize", h); return () => window.removeEventListener("resize", h); }, []);
  return w;
}
const pill = (active, m) => ({ background: active ? "#003366" : "#fff", border: "1px solid", borderColor: active ? "#003366" : "rgba(0,51,102,0.12)", color: active ? "#fff" : "rgba(0,51,102,0.55)", padding: m ? "7px 12px" : "8px 16px", fontFamily: "'DM Sans',sans-serif", fontSize: m ? "0.68rem" : "0.75rem", fontWeight: 500, cursor: "pointer", borderRadius: "100px", transition: "all 0.25s", flexShrink: 0 });
const inputStyle = m => ({ width: "100%", background: "#fff", border: "1px solid rgba(0,51,102,0.12)", borderRadius: "10px", padding: m ? "12px 14px" : "14px 16px", fontFamily: "'DM Sans'", fontSize: "0.9rem", color: "#003366", outline: "none" });
const labelStyle = { fontFamily: "'DM Sans'", fontSize: "0.78rem", fontWeight: 600, color: "#003366", marginBottom: "6px", display: "block" };

/* ============ HEADER ============ */
function Header({ scrolled, isMobile, onNav, currentPage }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const s = scrolled || currentPage !== "home";
  const items = [{ label: "Events", a: () => { setMenuOpen(false); onNav("events"); } }, { label: "Venues", a: () => { setMenuOpen(false); onNav("venues"); } }, { label: "Regions", a: () => { setMenuOpen(false); onNav("regions"); } }];
  return (
    <header style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 100, background: s || menuOpen ? "rgba(255,255,255,0.97)" : "transparent", backdropFilter: s || menuOpen ? "blur(20px)" : "none", borderBottom: s ? "1px solid rgba(0,51,102,0.08)" : "none", transition: "all 0.4s", padding: s ? "10px 0" : "16px 0" }}>
      <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "0 20px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div onClick={() => onNav("home")} style={{ display: "flex", alignItems: "baseline", gap: "8px", cursor: "pointer" }}>
          <span style={{ fontFamily: "'Playfair Display',Georgia,serif", fontSize: isMobile ? "1.25rem" : "1.5rem", fontWeight: 700, color: s || menuOpen ? "#003366" : "#fff", transition: "color 0.4s" }}>what's up</span>
          <span style={{ fontFamily: "'DM Sans'", fontSize: isMobile ? "0.55rem" : "0.65rem", fontWeight: 600, color: s || menuOpen ? "#2a7fff" : "rgba(255,255,255,0.8)", letterSpacing: "0.25em", textTransform: "uppercase" }}>Nova Scotia</span>
        </div>
        {isMobile ? <button onClick={() => setMenuOpen(!menuOpen)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: "1.5rem", padding: "4px 8px", color: s || menuOpen ? "#003366" : "#fff" }}>{menuOpen ? "✕" : "☰"}</button> : (
          <nav style={{ display: "flex", gap: "28px", alignItems: "center" }}>
            {items.map(i => <a key={i.label} onClick={i.a} style={{ color: s ? "rgba(0,51,102,0.5)" : "rgba(255,255,255,0.7)", textDecoration: "none", fontFamily: "'DM Sans'", fontSize: "0.8rem", letterSpacing: "0.06em", textTransform: "uppercase", fontWeight: 500, cursor: "pointer" }}>{i.label}</a>)}
            <button onClick={() => onNav("submit")} style={{ background: s ? "#003366" : "#fff", color: s ? "#fff" : "#003366", border: "none", padding: "9px 22px", fontFamily: "'DM Sans'", fontSize: "0.75rem", letterSpacing: "0.08em", textTransform: "uppercase", fontWeight: 600, cursor: "pointer", borderRadius: "100px" }}>Submit Event</button>
          </nav>
        )}
      </div>
      {isMobile && menuOpen && <div style={{ background: "#fff", padding: "16px 20px 24px", borderTop: "1px solid rgba(0,51,102,0.06)", display: "flex", flexDirection: "column", gap: "16px" }}>
        {items.map(i => <a key={i.label} onClick={i.a} style={{ color: "#003366", textDecoration: "none", fontFamily: "'DM Sans'", fontSize: "1rem", fontWeight: 500, cursor: "pointer" }}>{i.label}</a>)}
        <button onClick={() => { setMenuOpen(false); onNav("submit"); }} style={{ background: "#003366", color: "#fff", border: "none", padding: "12px 24px", fontFamily: "'DM Sans'", fontSize: "0.85rem", fontWeight: 600, borderRadius: "100px", cursor: "pointer", width: "100%" }}>Submit Event</button>
      </div>}
    </header>
  );
}

